const int N = 1e6 + 10;
EulerPrime er(N);
void solve()
{
	ll a, b, q; cin >> a >> b >> q;
	bool ok = 0;
	if (a > b)swap(a, b), ok = 1;
	var p = er.factorNumbers(b - a);
	sort(all(p));

	var Q = deque<pll>();
	var ans = vector<pll>(q + 1);
	fa(i, 1, q) {
		ll x; cin >> x;
		Q.pb({ x,i });
	}
	sort(all(Q));

	if (a == b) {
		fa(i, 1, q)cout << 1 << " " << 1 << endl;
		return;
	}

	ll k = 0;
	while (b - a > 1) {
		ll dis = 1e18, fp = 1;
		for (ll x : p) {
			if (x == 1 or (b - a) % x != 0)continue;
			ll d = (a + x - 1) / x * x - a;
			if (d < dis) {
				dis = d;
				fp = x;
			}
			else if (d == dis and x > fp)
				fp = x;
		}
		while (Q.size()) {
			ll cha = Q.front().px - k;
			if (cha > dis)break;
			else {
				if (cha == dis) {
					if (ok)ans[Q.front().py] = { (b + dis) / fp, (a + dis) / fp };
					else ans[Q.front().py] = { (a + dis) / fp, (b + dis) / fp };
				}
				else {
					if (ok)ans[Q.front().py] = { b + cha, a + cha };
					else ans[Q.front().py] = { a + cha, b + cha };
				}
				Q.pop_front();
			}
		}
		a = (a + dis) / fp;
		b = (b + dis) / fp;
		k += dis;
	}

	while (Q.size()) {
		ll cha = Q.front().px - k;
		if (ok)ans[Q.front().py] = { b + cha, a + cha };
		else ans[Q.front().py] = { a + cha, b + cha };
		Q.pop_front();
	}

	fa(i, 1, q)cout << ans[i].px << " " << ans[i].py << endl;
	return;
}
